// // This module implements a 2-bit shift register with asynchronous load and right-shift operations.
module shift_register(  
    input clk,  
    input load,  
    input [1:0] data_in,  
    output reg [1:0] q  
);  
    always @(posedge clk) begin  
        if (load)  
            q <= data_in;  
        else  
            q <= {q[0], 1'b0};  
    end  
endmodule
